import{_ as r,o,c as n,ai as s}from"./chunks/framework.CaiDwmc7.js";const h=JSON.parse('{"title":"HTTP 与 HTTPS 协议","description":"","frontmatter":{},"headers":[],"relativePath":"network-linux/http.md","filePath":"network-linux/http.md"}'),i={name:"network-linux/http.md"};function l(g,t,e,a,T,p){return o(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="http-与-https-协议" tabindex="-1">HTTP 与 HTTPS 协议 <a class="header-anchor" href="#http-与-https-协议" aria-label="Permalink to “HTTP 与 HTTPS 协议”">​</a></h1><hr><h3 id="❓-面试官-在浏览器输入-url-到页面显示-经历了什么过程" tabindex="-1">❓ 面试官：在浏览器输入 URL 到页面显示，经历了什么过程？ <a class="header-anchor" href="#❓-面试官-在浏览器输入-url-到页面显示-经历了什么过程" aria-label="Permalink to “❓ 面试官：在浏览器输入 URL 到页面显示，经历了什么过程？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 这是一个从网络寻址、建立连接、数据传输到浏览器渲染的完整链路过程。</p><p><strong>📝 详细步骤解析：</strong></p><ol><li><strong>DNS 解析</strong>：浏览器先查看本地缓存，没有的话找本地 host 文件，再找本地 DNS 服务器，一层层把域名（如 <code>www.baidu.com</code>）解析成真实的 IP 地址。</li><li><strong>TCP 连接</strong>：拿到 IP 后，浏览器通过 TCP 的<strong>三次握手</strong>与服务器的 80（HTTP）或 443（HTTPS）端口建立连接。</li><li><strong>HTTPS 的 TLS 握手（如果是 HTTPS）</strong>：进行加密协议的握手，验证服务器证书，协商对称加密的密钥。</li><li><strong>发送 HTTP 请求</strong>：浏览器组装 HTTP 请求报文（请求行、请求头、请求体）发送给服务器。</li><li><strong>服务器处理</strong>：后端（如 SpringBoot、Nginx）接收请求，执行业务逻辑，返回 HTTP 响应报文（状态码、响应头、响应体 HTML）。</li><li><strong>浏览器渲染</strong>：浏览器拿到 HTML，解析 DOM 树、CSSOM 树，合并成渲染树，进行布局（Layout）和绘制（Paint），最终展示给用户。</li><li><strong>连接关闭</strong>：如果是 HTTP/1.0 且没有 Keep-Alive，直接<strong>四次挥手</strong>断开。现代 HTTP/1.1 默认 Keep-Alive 会保持连接一段时间。</li></ol><hr><h3 id="❓-面试官-常见的-http-状态码有哪些-502-和-504-有什么区别" tabindex="-1">❓ 面试官：常见的 HTTP 状态码有哪些？502 和 504 有什么区别？ <a class="header-anchor" href="#❓-面试官-常见的-http-状态码有哪些-502-和-504-有什么区别" aria-label="Permalink to “❓ 面试官：常见的 HTTP 状态码有哪些？502 和 504 有什么区别？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（分类记忆）：</strong> 1xx（信息），2xx（成功），3xx（重定向），4xx（客户端错误），5xx（服务端错误）。</p><p><strong>📝 核心高频状态码：</strong></p><ul><li><strong>200 OK</strong>：请求成功。</li><li><strong>301 Moved Permanently</strong>：永久重定向。比如旧域名作废，SEO 搜索引擎会更新地址。</li><li><strong>302 Found</strong>：临时重定向。比如未登录用户访问后台，被临时跳转到登录页。</li><li><strong>400 Bad Request</strong>：前端传的参数类型或格式不对，后端 Spring 抛了异常。</li><li><strong>401 Unauthorized</strong>：未授权，没带 Token 或者 Token 错误。</li><li><strong>403 Forbidden</strong>：禁止访问，有 Token 但权限不够。</li><li><strong>404 Not Found</strong>：请求的接口路径写错了。</li><li><strong>500 Internal Server Error</strong>：后端代码报 NullPointerException 等未捕获异常了。</li></ul><p><strong>🌟 追问：502 和 504 的区别？（实战经验）</strong> 这两者通常发生在使用 Nginx 做反向代理的架构中。</p><ul><li><strong>502 Bad Gateway（网关错误）</strong>：Nginx 转发请求给后端的 Tomcat，但 Tomcat 挂了（进程死了、端口不通），Nginx 连接不上后端，就会返回 502。</li><li><strong>504 Gateway Timeout（网关超时）</strong>：Nginx 连接上了 Tomcat，但 Tomcat 处理这个请求太慢了（比如慢 SQL 查了 30 秒），超过了 Nginx 配置的超时时间，Nginx 等得不耐烦了，主动断开并返回 504。</li></ul><hr><h3 id="❓-面试官-get-和-post-的区别是什么" tabindex="-1">❓ 面试官：GET 和 POST 的区别是什么？ <a class="header-anchor" href="#❓-面试官-get-和-post-的区别是什么" aria-label="Permalink to “❓ 面试官：GET 和 POST 的区别是什么？”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 常见“八股文”回答（表层）：</strong></p><ul><li>GET 参数放在 URL 后面，POST 参数放在请求体（Body）里。</li><li>GET 参数有长度限制（受浏览器和服务器限制），POST 没有。</li><li>GET 是不安全的（密码会被看到），POST 相对安全。</li></ul><p><strong>🌟 高分回答（深入底层与 RESTful 语义）：</strong> “除了表面的不同，它们最本质的区别在于<strong>语义</strong>和<strong>幂等性</strong>。”</p><ul><li><strong>语义上</strong>：GET 用于<strong>获取数据</strong>，POST 用于<strong>提交数据</strong>（新建资源）。</li><li><strong>幂等性上</strong>：GET 请求是<strong>幂等</strong>的（不管请求多少次，服务端的资源状态都不变）。POST 是<strong>非幂等</strong>的（每次提交可能都会产生一条新订单）。</li><li><strong>缓存机制</strong>：因为 GET 是只读和幂等的，浏览器和 CDN 默认会主动缓存 GET 请求的结果；而 POST 请求默认不会被缓存。</li><li><strong>底层网络（TCP层，加分项）</strong>：绝大多数浏览器发送 GET 时，会把 Header 和 Data 放在一个 TCP 数据包里发送；而有些老版本的浏览器发送 POST 时，会先发 Header（收到 100 Continue 响应后），再发 Data 数据包。</li></ul><hr><h3 id="❓-面试官-https-为什么安全-它是如何加密的-对称加密与非对称加密" tabindex="-1">❓ 面试官：HTTPS 为什么安全？它是如何加密的？（对称加密与非对称加密） <a class="header-anchor" href="#❓-面试官-https-为什么安全-它是如何加密的-对称加密与非对称加密" aria-label="Permalink to “❓ 面试官：HTTPS 为什么安全？它是如何加密的？（对称加密与非对称加密）”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> HTTPS 在 HTTP 和 TCP 之间加了一层 <strong>SSL/TLS 层</strong>。它使用<strong>非对称加密来协商出一个安全的密钥</strong>，然后再用这个<strong>安全的密钥去进行对称加密传输真正的数据</strong>。这种“混合加密”既保证了绝对安全，又保证了传输速度。</p><p><strong>📝 详细加密握手过程（非常核心）：</strong></p><ol><li>客户端向服务器索要<strong>公钥</strong>。</li><li>服务器返回自己的<strong>数字证书</strong>（包含了服务器的公钥和权威机构 CA 的签名）。</li><li>客户端用操作系统里内置的 CA 根证书，<strong>验证这个数字证书的真伪</strong>。确认没被篡改后，提取出里面的公钥。</li><li>客户端自己随机生成一个<strong>“对称加密的密钥（随机数）”</strong>。</li><li>客户端用刚才拿到的<strong>公钥</strong>，把这个<strong>随机数加密</strong>，发给服务器。（非对称加密的特性：只有服务器的私钥能解开，黑客截获了也没用）。</li><li>服务器收到后用自己的<strong>私钥解密</strong>，得到了这个“对称加密密钥”。</li><li><strong>大功告成</strong>：现在双方都有了相同的“对称加密密钥”。接下来所有的 HTTP 业务数据，都用这个对称密钥进行极速的加解密传输。</li></ol><p><strong>🌟 为什么不一直用非对称加密？</strong> 因为非对称加密的算法极其复杂，如果在每次传输业务图片、JSON 数据时都用它，会导致 CPU 爆炸，网页加载极其缓慢。所以非对称加密只在<strong>刚建连阶段</strong>用来交换“钥匙”，后面大量的数据传输用轻量级的对称加密。</p>',29)])])}const d=r(i,[["render",l]]);export{h as __pageData,d as default};
